const input = $node["Standup Input"].json;
const body = input.body ?? input;
const projectName = body.project_name || body.projectName || body.project || "";
const meetingMinutes = body.meeting_minutes || body.meetingMinutes || body.minutes || "";
const blockers = Array.isArray(body.blockers) ? body.blockers : (body.blockers ? [body.blockers] : []);
const reportDate = body.report_date || body.date || new Date().toISOString().slice(0, 10);

if (!projectName) throw new Error("project_name is required");

const prompt = `You are an operations assistant for a Scrum board.

Extract a strict JSON object from the daily standup notes.

INPUTS
Project name: ${projectName}
Report date: ${reportDate}
Meeting minutes:
${meetingMinutes}

Blockers:
${JSON.stringify(blockers, null, 2)}

Return ONLY valid JSON with this exact shape:
{
  "project_name": string,
  "summary": string,
  "completed_tasks": [
    {
      "user_story_id": string | null,
      "user_story_title": string,
      "priority": "Low" | "Medium" | "High",
      "assignee_email": string | null,
      "trello_card_id": string | null,
      "behind_schedule": boolean,
      "current_status": string | null,
      "target_status": "Done",
      "reason": string
    }
  ],
  "notifications": [
    {
      "user_story_id": string | null,
      "user_story_title": string,
      "assignee_email": string | null,
      "priority": "Low" | "Medium" | "High",
      "behind_schedule": true,
      "message": string,
      "reason": string
    }
  ]
}

Rules:
- completed_tasks must include any task explicitly marked done, finished, merged, shipped, or completed in the minutes.
- behind_schedule must be true when the person is blocked, late, waiting on dependency, or missed a due date.
- notifications must include all behind schedule assigned tasks.
- priority should be High for blockers that stop delivery, Medium for normal risk, Low for minor delays.
- Return JSON only. No markdown. No explanation.

Project name to normalize in output: ${projectName}`;

return [{
  json: {
    project_name: projectName,
    meeting_minutes: meetingMinutes,
    blockers,
    report_date: reportDate,
    prompt,
    bodyForOllama: {
      model: "gpt-oss:120b",
      prompt,
      format: "json",
      stream: false
    }
  }
}];

function stripFences(s) {
  if (!s) return s;
  s = String(s).trim();
  if (s.startsWith("```")) {
    s = s.replace(/^```(?:json)?\s*/, "").replace(/\s*```$/, "");
  }
  return s;
}

function readResponse(j) {
  if (!j) return null;
  if (typeof j.response === "string") return j.response;
  if (typeof j.text === "string") return j.text;
  if (typeof j.output === "string") return j.output;
  if (Array.isArray(j) && j[0]) return readResponse(j[0]);
  if (j.choices && j.choices[0]?.message?.content) return j.choices[0].message.content;
  return null;
}

const llmOut = $node["LLM Node"].json;
const raw = readResponse(llmOut);
if (!raw) throw new Error("LLM response not found");

let parsed;
try {
  parsed = JSON.parse(stripFences(raw));
} catch (e) {
  throw new Error("Failed to parse standup JSON: " + e.message);
}

// Also get the raw blockers from the build node (original array)
const rawBlockers = $node["buildStandupPrompt"].json.blockers || [];

return [{
  json: {
    project_name: parsed.project_name || $node["buildStandupPrompt"].json.project_name,
    summary: parsed.summary || "",
    completed_tasks: Array.isArray(parsed.completed_tasks) ? parsed.completed_tasks : [],
    notifications: Array.isArray(parsed.notifications) ? parsed.notifications : [],
    raw_blockers: rawBlockers
  }
}];

// Helper: extract story ID from card name (e.g., "US-001: Login page" -> "US-001")
function extractStoryId(cardName) {
  const match = String(cardName || "").match(/^([A-Z]{2,}-\d+)/);
  return match ? match[1] : null;
}

// Get data from previous nodes
const parsed = $node["ParseLLM"].json;
const project = $node["Get Project"].json;
const cards = $items("Get Trello Cards").map(i => i.json);
const lists = $items("Get Board Lists").map(i => i.json);

// Find the "Done" list
const doneList = lists.find(l => /^(done|completed?|closed)$/i.test(String(l.name || "").trim()))
  || lists.find(l => /done|complete|close/i.test(String(l.name || "")))
  || null;

// Find "Blockers" list or fallback
const blockersList = lists.find(l => /^blockers?$/i.test(String(l.name || "").trim()))
  || lists.find(l => /backlog/i.test(String(l.name || "")))
  || lists[0];

// Build maps for quick lookup
const cardById = new Map();
const cardByStoryId = new Map();
const cardByName = new Map();

for (const card of cards) {
  cardById.set(card.id, card);
  const storyId = extractStoryId(card.name);
  if (storyId) cardByStoryId.set(storyId, card);
  cardByName.set(card.name.toLowerCase(), card);
}

function resolveCard(task) {
  if (!task) return null;
  if (task.trello_card_id) return cardById.get(task.trello_card_id);
  if (task.user_story_id) return cardByStoryId.get(task.user_story_id);
  if (task.user_story_title) return cardByName.get(task.user_story_title.toLowerCase());
  return null;
}

// Grouped arrays
const moveItems = [];
const notifyItems = [];
const blockerItems = [];
const completedStoryIds = [];

// 1. Process completed tasks -> move group
for (const task of (parsed.completed_tasks || [])) {
  const card = resolveCard(task);
  if (!card) continue;
  if (!doneList?.id) continue;
  const alreadyDone = card.idList === doneList.id;
  if (!alreadyDone) {
    moveItems.push({
      card_id: card.id,
      done_list_id: doneList.id,
      story_id: extractStoryId(card.name) || task.user_story_id,
      story_title: card.name,
      project_id: project.id
    });
    const storyId = extractStoryId(card.name);
    if (storyId) completedStoryIds.push(storyId);
  }
}

// 2. Process notifications -> notify group
for (const note of (parsed.notifications || [])) {
  const card = resolveCard(note);
  if (!card) continue;
  const memberIds = card.idMembers || [];
  if (memberIds.length === 0) continue;
  notifyItems.push({
    card_id: card.id,
    story_id: extractStoryId(card.name) || note.user_story_id,
    story_title: card.name,
    member_ids: memberIds,
    priority: note.priority || "Medium",
    message: note.message || note.reason || "Task is behind schedule.",
    reason: note.reason || "",
    project_id: project.id,
    project_name: parsed.project_name 
  });
}

// 3. Process blockers -> blocker group
const blockers = parsed.raw_blockers || [];
for (const blockerText of blockers) {
  if (!blockerText || blockerText.trim() === "") continue;
  blockerItems.push({
    title: `Blocker: ${blockerText.substring(0, 100)}`,
    description: `Reported on ${parsed.report_date || new Date().toISOString().slice(0, 10)} during daily standup.\n\nDetails: ${blockerText}`,
    list_id: blockersList?.id,
    project_id: project.id
  });
}

// Output items: one per group
const outputItems = [];

if (moveItems.length > 0) {
  outputItems.push({
    json: {
      type: "move",
      items: moveItems,
      completedStoryIds: completedStoryIds,  // optional: include for DB update later
      project_id: project.id
    }
  });
}

if (notifyItems.length > 0) {
  outputItems.push({
    json: {
      type: "notify",
      items: notifyItems,
      project_id: project.id

    }
  });
}

if (blockerItems.length > 0) {
  outputItems.push({
    json: {
      type: "create_blocker",
      items: blockerItems,
      project_id: project.id
    }
  });
}

// Always output a database update item (even if no moves)
outputItems.push({
  json: {
    type: "update_db",
    completedStoryIds: completedStoryIds,
    project_id: project.id,
    us_pending: project.us_pending || [],
    us_done: project.us_done || []
  }
});

return outputItems;

