// Email error handler
console.error('Email failed to send:', $input.item().json);
return [{ json: { email_error: true, original: $input.item().json } }];

// After all move actions, update project's us_pending and us_done in DB
const prepNode = $node["Prepare Actions"].json;
const completedIds = prepNode.completedStoryIds || [];
const projectId = prepNode.project_id;
const oldPending = prepNode.us_pending || [];
const oldDone = prepNode.us_done || [];

// Remove completed IDs from pending, add to done
const newPending = oldPending.filter(id => !completedIds.includes(id));
const newDone = [...new Set([...oldDone, ...completedIds])];

// Return as item for PostgreSQL node
return [{
  json: {
    project_id: projectId,
    us_pending: newPending,
    us_done: newDone
  }
}];
